// Constants
var TAU = 6.283;          // 2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // √(1/2)

// Simulation parameters
var params = {
    attractionRange: 4000,      // 0xFA0
    springBaseCoeff: 0.004,
    amplification: 0.92,        // damping/velocity retention factor
    gravityStrength: 0.0003,
    streamMaxCount: 40,         // 0x28
    streamDecay: 0.04,
    theta: 0.06                 // camera smoothing factor
};

// Nodes
var nodes = [
    { id: 'hub',       label: 'Hub',       r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',     label: 'Alpha',     r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',      label: 'Beta',      r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',     label: 'Gamma',     r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',     label: 'Delta',     r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon',   label: 'Epsilon',   r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Spring connections (edges)
var edges = [
    { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
    { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
    { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle stream
var particles = [];
var tick = 0;

// Find node by ID
function findNode(id) {
    for (var i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// Physics step: repulsion, spring forces, gravity, damping, integration
function physicsStep() {
    // Coulomb-style repulsion between all node pairs
    for (var i = 0; i < nodes.length; i++) {
        for (var j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx * dx + dy * dy) || 1;
            var force = params.attractionRange / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // Spring (Hooke's law) forces along edges
    for (var e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        if (!nodeA || !nodeB) continue;
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx * dx + dy * dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || params.springBaseCoeff) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // Per-node: gravity toward center (400,300), damping, position integration
    for (var n = 0; n < nodes.length; n++) {
        nodes[n].vx += (400 - nodes[n].x) * params.gravityStrength;
        nodes[n].vy += (300 - nodes[n].y) * params.gravityStrength;
        nodes[n].vx *= params.amplification;  // damping
        nodes[n].vy *= params.amplification;
        nodes[n].x += nodes[n].vx;
        nodes[n].y += nodes[n].vy;
    }
}

// Spawn a particle from a random node
function spawnParticle() {
    if (particles.length >= params.streamMaxCount) return;
    var node = nodes[Math.floor(Math.random() * nodes.length)];
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT1_2;
    particles.push({
        x: node.x,
        y: node.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + (Math.random() * PHI) * SQRT1_2
    });
}

// Update particles: move, decay, remove expired
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.age++;
        p.vx *= (1 - params.streamDecay * 0.125);
        p.vy *= (1 - params.streamDecay * 0.125);
        p.x += p.vx;
        p.y += p.vy;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// Smooth camera tracking
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * params.theta;
    camera.y += (cameraTarget.y - camera.y) * params.theta;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * params.theta;
}

// Main loop
function mainLoop() {
    physicsStep();
    updateParticles();
    updateCamera();
    if (tick % 3 === 0) spawnParticle();
    tick++;
}

setInterval(mainLoop, 16);  // ~60 FPS
```

## Algorithm Summary

This is a **force-directed graph layout simulation** with:

1. **Coulomb repulsion** between all node pairs (inverse-square law)
2. **Hooke's law springs** along edges pulling connected nodes toward rest lengths
3. **Central gravity** pulling all nodes toward (400, 300)
4. **Velocity damping** (0.92 per tick) for stability
5. **Decorative particle streams** spawned from random nodes, drifting and fading
6. **Smooth camera interpolation** toward a target position

The graph is a **hub-and-spoke topology**: a central "Hub" node connected to five satellite nodes (Alpha, Beta, Gamma, Delta, Epsilon), with three cross-links (Alpha↔Beta, Gamma↔Delta, Alpha↔Epsilon).
